# EVOLVE-BLOCK-START
import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List


def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    # Remove edges with None cost
    bad_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(bad_edges)
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))

    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Build a Steiner tree for minimum-cost broadcast
    # Strategy: greedy approach - iteratively connect the nearest unconnected
    # destination to the existing tree (from any tree node)

    terminals = [src] + list(dsts)

    # Precompute shortest paths from each terminal to all other nodes
    sp_data = {}  # terminal -> {node: (cost, path)}
    for t in terminals:
        try:
            lengths, paths = nx.single_source_dijkstra(h, t, weight='cost')
            sp_data[t] = (lengths, paths)
        except Exception:
            sp_data[t] = ({}, {})

    # Greedy Steiner tree construction
    # Start with src in the tree, iteratively add cheapest destination
    tree_nodes = {src}
    tree_edges = []  # list of (u, v) directed edges
    remaining_dsts = set(dsts)

    while remaining_dsts:
        best_cost = float('inf')
        best_dst = None
        best_path = None

        for dst in remaining_dsts:
            # Find cheapest path from any tree node to this destination
            for tree_node in tree_nodes:
                lengths, paths = sp_data[tree_node]
                if dst in lengths and lengths[dst] < best_cost:
                    best_cost = lengths[dst]
                    best_dst = dst
                    best_path = paths[dst]

        if best_dst is None:
            # Fallback: try direct dijkstra for unreachable destinations
            for dst in remaining_dsts:
                try:
                    path = nx.dijkstra_path(h, src, dst, weight='cost')
                    cost = nx.dijkstra_path_length(h, src, dst, weight='cost')
                    if cost < best_cost:
                        best_cost = cost
                        best_dst = dst
                        best_path = path
                except nx.NetworkXNoPath:
                    continue
            if best_dst is None:
                break

        # Add path edges to tree
        for i in range(len(best_path) - 1):
            tree_nodes.add(best_path[i])
            tree_nodes.add(best_path[i + 1])
            tree_edges.append((best_path[i], best_path[i + 1]))

        remaining_dsts.discard(best_dst)

    # Build directed tree graph from collected edges
    tree_graph = nx.DiGraph()
    for u, v in tree_edges:
        if h.has_edge(u, v):
            tree_graph.add_edge(u, v, **h[u][v])

    # For each destination, find path from src in the tree
    for dst in dsts:
        try:
            path = nx.shortest_path(tree_graph, src, dst)
        except nx.NetworkXNoPath:
            # Fallback to shortest path in full graph
            try:
                path = nx.dijkstra_path(h, src, dst, weight='cost')
            except nx.NetworkXNoPath:
                continue

        for i in range(len(path) - 1):
            s, t = path[i], path[i + 1]
            for j in range(num_partitions):
                bc_topology.append_dst_partition_path(dst, j, [s, t, G[s][t]])

    return bc_topology


class SingleDstPath(Dict):
    partition: int
    edges: List[List]  # [[src, dst, edge data]]


class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, SingleDstPath] = None):
        self.src = src  # single str
        self.dsts = dsts  # list of strs
        self.num_partitions = num_partitions

        # dict(dst) --> dict(partition) --> list(nx.edges)
        # example: {dst1: {partition1: [src->node1, node1->dst1], partition 2: [src->dst1]}}
        if paths is not None:
            self.paths = paths
            self.set_graph()
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        print(f"now the set path is: {self.paths}")
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List[List]):
        """
        Set paths for partition = partition to reach dst
        """
        partition = str(partition)
        self.paths[dst][partition] = paths

